import { cn } from "@/lib/utils";

type AssetBadgeProps = {
  symbol: string;
  color: string;
  size?: "sm" | "md";
};

export function AssetBadge({ symbol, color, size = "md" }: AssetBadgeProps) {
  const text = symbol === "Bitcoin" ? "B" : symbol.slice(0, 1);

  return (
    <span
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-full text-xs text-white  shadow-[inset_0_1px_2px_1px_rgba(255,255,255,0.2),inset_0px_-1px_2px_1px_rgba(0,0,0,0.08)] ",
        size === "sm" ? "size-6" : "size-9",
        color,
        symbol === "ETH" || symbol === "Ethereum" ? "text-slate-700" : ""
      )}
    >
      {text}
    </span>
  );
}

import { ArrowRight, ChevronsUpDown, MoreVertical, Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { AssetBadge } from "./asset-badge"; 

type Asset = {
  asset: string;
  balance: string;
  value: string;
  color: string;
};

type AssetTableCardProps = {
  title: string;
  assets: Asset[];
  action: string;
  valueLabel: string;
  external?: boolean;
};

export function AssetTableCard({
  title,
  assets,
  action,
  valueLabel,
  external,
}: AssetTableCardProps) {
  return (
    <Card className="rounded-2xl bg-card dark:bg-muted shadow-primary ring-0 py-4 p-2 gap-2">
      <CardHeader className="flex items-center justify-between px-2  ">
        <CardTitle className="text-lg font-medium">{title}</CardTitle>
        <Button variant="ghost" size="icon-sm" aria-label={`${title} menu`}>
          <MoreVertical className="size-4" />
        </Button>
      </CardHeader>
      <CardContent className="px-4 p-2 rounded-lg bg-muted/40 dark:bg-black">
        <div className="border rounded-md overflow-hidden ">
          <Table >
            <TableHeader className="bg-muted rounded-md">
              <TableRow className="hover:bg-muted rounded-md   ">
                <TableHead className="h-9 text-sm font-medium">Asset</TableHead>
                <TableHead className="h-9 text-sm font-medium">
                  <span className="inline-flex items-center gap-1">
                    Balance
                    <ChevronsUpDown className="size-4" />
                  </span>
                </TableHead>
                <TableHead className="h-9 text-sm font-medium">
                  <span className="inline-flex items-center gap-1">
                    {valueLabel}
                    <ChevronsUpDown className="size-4" />
                  </span>
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody >
              {assets.map((asset) => (
                <TableRow key={asset.asset} className="border-border/70 border-y bg-white dark:bg-black hover:dark:bg-muted">
                  <TableCell className="h-12 bg-transparent">
                    <span className="inline-flex items-center gap-3 font-medium ">
                      <AssetBadge symbol={asset.asset} color={asset.color} size="sm" />
                      {asset.asset}
                    </span>
                  </TableCell>
                  <TableCell className="h-12 font-medium">{asset.balance}</TableCell>
                  <TableCell className="h-12 font-medium">{asset.value}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
        <Button variant="outline" className="mt-4 h-9 w-full bg-muted dark:bg-muted font-normal">
          {action}
          {external ? <ArrowRight className="size-4" /> : <Plus className="size-4" />}
        </Button>
      </CardContent>
    </Card>
  );
}

"use client";

import {
  Area,
  AreaChart,
  CartesianGrid,
  ResponsiveContainer,
  XAxis,
  YAxis,
} from "recharts";
import { apyData, portfolioData } from "../../data";

export function PortfolioChart() {
  return (
    <ResponsiveContainer width="100%" height="100%">
      <AreaChart data={portfolioData} >
        <defs>
          <linearGradient id="portfolioFill" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="var(--chart-1)" stopOpacity={0.55} />
            <stop offset="100%" stopColor="var(--chart-1)" stopOpacity={0.02} />
          </linearGradient>
        </defs>
        <CartesianGrid stroke="var(--border)" strokeOpacity={0.25} vertical />
        <XAxis
          dataKey="month"
          axisLine={false}
          tickLine={false}
          interval={2}
          tick={{ fill: "var(--muted-foreground)", fontSize: 13 }}
        />
        <YAxis
          axisLine={false}
          tickLine={false}
          width={54}
          ticks={[0, 50000, 100000, 150000, 200000, 250000]}
          tickFormatter={(value) => `${Number(value) / 1000}K`}
          tick={{ fill: "var(--muted-foreground)", fontSize: 13 }}
        />
        <Area
          type="linear"
          dataKey="value"
          stroke="var(--chart-1)"
          strokeWidth={4}
          fill="url(#portfolioFill)"
          activeDot={false}
          dot={false}
        />
      </AreaChart>
    </ResponsiveContainer>
  );
}

export function ApySparkline() {
  return (
    <ResponsiveContainer width="100%" height="100%">
      <AreaChart data={apyData} margin={{ top: 8, right: 0, left: 0, bottom: 0 }}>
        <defs>
          <linearGradient id="apyFill" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="var(--color-emerald-400)" stopOpacity={0.45} />
            <stop offset="100%" stopColor="var(--color-emerald-400)" stopOpacity={0} />
          </linearGradient>
        </defs>
        <XAxis dataKey="month" hide />
        <Area
          type="monotone"
          dataKey="value"
          stroke="var(--color-emerald-400)"
          strokeWidth={2}
          fill="url(#apyFill)"
          dot={false}
          activeDot={false}
        />
      </AreaChart>
    </ResponsiveContainer>
  );
}

